// n8n Code Node - PM2.5 Statistics Calculator (Integer Output)
// This code calculates min, max, average, and median from the PM2.5 array as integers

const items = $input.all();
let pm25Values = [];

// Extract PM2.5 values from each item
for (const item of items) {
  // Check for different possible property names
  if (item.json.PM25) {
    if (Array.isArray(item.json.PM25)) {
      pm25Values = pm25Values.concat(item.json.PM25);
    } else {
      pm25Values.push(item.json.PM25);
    }
  }
  if (item.json.pm25) {
    if (Array.isArray(item.json.pm25)) {
      pm25Values = pm25Values.concat(item.json.pm25);
    } else {
      pm25Values.push(item.json.pm25);
    }
  }
  if (item.json.PM2_5) {
    if (Array.isArray(item.json.PM2_5)) {
      pm25Values = pm25Values.concat(item.json.PM2_5);
    } else {
      pm25Values.push(item.json.PM2_5);
    }
  }
  if (item.json.pm2_5) {
    if (Array.isArray(item.json.pm2_5)) {
      pm25Values = pm25Values.concat(item.json.pm2_5);
    } else {
      pm25Values.push(item.json.pm2_5);
    }
  }
}

// Convert all values to numbers and filter out invalid entries
pm25Values = pm25Values
  .map(val => parseFloat(val))
  .filter(val => !isNaN(val));

// Function to calculate integer-based statistics
function calculateStatistics(values) {
  if (values.length === 0) {
    return { 
      error: "No valid PM2.5 values found", 
      count: 0 
    };
  }

  const sortedValues = [...values].sort((a, b) => a - b);

  const min = Math.round(Math.min(...values));
  const max = Math.round(Math.max(...values));
  const sum = values.reduce((acc, val) => acc + val, 0);
  const average = Math.round(sum / values.length);

  let median;
  const middleIndex = Math.floor(sortedValues.length / 2);

  if (sortedValues.length % 2 === 0) {
    median = Math.round((sortedValues[middleIndex - 1] + sortedValues[middleIndex]) / 2);
  } else {
    median = Math.round(sortedValues[middleIndex]);
  }

  // Calculate additional PM2.5 specific metrics
  const nonZeroValues = values.filter(v => v > 0);
  const nonZeroCount = nonZeroValues.length;
  const nonZeroPercentage = Math.round((nonZeroCount / values.length) * 100);

  // AQI categories for PM2.5 (μg/m³) - ensure integer counts
  const goodCount = values.filter(v => v >= 0 && v <= 12).length;
  const moderateCount = values.filter(v => v > 12 && v <= 35).length;
  const unhealthySensitiveCount = values.filter(v => v > 35 && v <= 55).length;
  const unhealthyCount = values.filter(v => v > 55 && v <= 150).length;
  const veryUnhealthyCount = values.filter(v => v > 150 && v <= 250).length;
  const hazardousCount = values.filter(v => v > 250).length;

  return {
    min: Number(min),
    max: Number(max),
    average: Number(average),
    median: Number(median),
    count: Number(values.length),
    nonZeroCount: Number(nonZeroCount),
    nonZeroPercentage: Number(nonZeroPercentage),
    goodCount: Number(goodCount),
    moderateCount: Number(moderateCount),
    unhealthySensitiveCount: Number(unhealthySensitiveCount),
    unhealthyCount: Number(unhealthyCount),
    veryUnhealthyCount: Number(veryUnhealthyCount),
    hazardousCount: Number(hazardousCount),
    allValues: values.map(v => Math.round(v))
  };
}

const statistics = calculateStatistics(pm25Values);

// Create clean output with camelCase naming to avoid n8n parsing issues
return [{
  json: {
    pm25Statistics: {
      minimum: Number(statistics.min || 0),
      maximum: Number(statistics.max || 0),
      average: Number(statistics.average || 0),
      median: Number(statistics.median || 0),
      totalCount: Number(statistics.count || 0),
      nonZeroCount: Number(statistics.nonZeroCount || 0),
      nonZeroPercentage: Number(statistics.nonZeroPercentage || 0)
    },
    aqiDistribution: {
      good: Number(statistics.goodCount || 0),
      moderate: Number(statistics.moderateCount || 0),
      unhealthySensitive: Number(statistics.unhealthySensitiveCount || 0),
      unhealthy: Number(statistics.unhealthyCount || 0),
      veryUnhealthy: Number(statistics.veryUnhealthyCount || 0),
      hazardous: Number(statistics.hazardousCount || 0)
    },
    rawPm25Values: statistics.allValues || [],
    calculatedAt: new Date().toISOString()
  }
}];

